-- OAuth / token metadata for identities (BYOL + future OAuth task 08).
-- Forward-only: append new migrations; do not edit this file after it has shipped.

ALTER TABLE identities
ADD COLUMN refresh_token_ciphertext BYTEA,
ADD COLUMN token_expires_at TIMESTAMPTZ,
ADD COLUMN git_provider TEXT,
ADD COLUMN git_base_url TEXT;

COMMENT ON COLUMN identities.git_provider IS 'manual | oauth_github | oauth_gitlab (API_OVERVIEW §4a / §4b)';
